PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE car_form_entry (form_entry_id varchar(36) not null, car_id varchar(36) not null);
CREATE TABLE cars (id varchar(36) not null, created_at timestamp not null, created_by varchar(255) not null, deleted boolean not null, updated_at timestamp not null, updated_by varchar(255) not null, name varchar(255) not null, parent_id varchar(36), primary key (id));
CREATE TABLE form_entries (id varchar(36) not null, created_at timestamp not null, created_by varchar(255) not null, deleted boolean not null, updated_at timestamp not null, updated_by varchar(255) not null, contact_phone varchar(255) not null, full_name varchar(255) not null, valid_driving_license boolean not null, primary key (id));
COMMIT;
